# 🔐 RAILWAY SECRETS CHECKLIST
# Copy these EXACT variable names to Railway Dashboard → Variables

# =================================
# ✅ CRITICAL - MUST SET FIRST
# =================================

# 1. Database (Auto-generated by Railway PostgreSQL plugin)
DATABASE_URL=postgresql://username:password@host:port/database

# 2. Stripe Payment Processing
STRIPE_SECRET_KEY=sk_live_51...
STRIPE_PUBLISHABLE_KEY=pk_live_51...
STRIPE_WEBHOOK_SECRET=whsec_...

# 3. Stripe Product Price IDs (Create these in Stripe Dashboard first)
STRIPE_BASIC_WEEKLY_PRICE_ID=price_1Rg6fnJF6bibA8nesbJ1RvxA
STRIPE_PRO_WEEKLY_PRICE_ID=price_1Rtf6CJF6bibA8nef9w5LhLE
STRIPE_PRO_ANNUAL_PRICE_ID=price_1Rtf9YJF6bibA8nemK14siZ5

# 4. Firebase Authentication
FIREBASE_PROJECT_ID=your-production-project-id

# Option 1: GOOGLE_CREDENTIALS (Recommended)
GOOGLE_CREDENTIALS={"type":"service_account","project_id":"your-production-project-id","private_key_id":"...","private_key":"-----BEGIN PRIVATE KEY-----\n...\n-----END PRIVATE KEY-----\n","client_email":"firebase-adminsdk-xxxxx@your-project.iam.gserviceaccount.com",...}

# Option 2: Individual Variables (Alternative)
FIREBASE_PRIVATE_KEY="-----BEGIN PRIVATE KEY-----\nYOUR_MULTI_LINE_KEY_HERE\n-----END PRIVATE KEY-----\n"
FIREBASE_CLIENT_EMAIL=firebase-adminsdk-xxxxx@your-project.iam.gserviceaccount.com

# 5. Application Security
NODE_ENV=production
SESSION_SECRET=your-32-character-minimum-secure-random-string

# 6. Storage Configuration
STORAGE_PATH=/app/storage

